#!/usr/bin/env npx tsx
/**
 * Repair premium product-chain formulas via DeepSeek.
 *
 * Targets premium tools whose formulas are simple multiplication chains
 * (normalized_product / adjustment_factor patterns) and replaces them
 * with domain-accurate formulas generated by DeepSeek.
 *
 * Usage:
 *   npx tsx scripts/deepseek/repair-premium-product-chain.ts --dry-run --limit=3
 *   npx tsx scripts/deepseek/repair-premium-product-chain.ts --limit=10
 *   npx tsx scripts/deepseek/repair-premium-product-chain.ts --all
 *   npx tsx scripts/deepseek/repair-premium-product-chain.ts --slug=irr-calculator
 */
import fs from "node:fs";
import path from "node:path";
import { compileFormulaExpression } from "@/lib/generated-tools/compile-formula-expression";
import { toSafeVarName } from "@/lib/generated-tools/export-names";
import {
  validateIndustrialSchema,
} from "@/lib/generated-tools/validate-industrial-schema";
import { loadEnvLocal, PROJECT_ROOT } from "./load-env";
import { resolveDeepSeekApiKey } from "./deepseek-key-pool";
import { repairJsonText } from "./schema-json-utils";
import { generateFromSchemaFile } from "./generate-from-schema";

loadEnvLocal();

const SCHEMAS_DIR = path.join(PROJECT_ROOT, "generated", "schemas");
const GENERATED_DIR = path.join(PROJECT_ROOT, "generated");
const PROGRESS_PATH = path.join(PROJECT_ROOT, "scripts/.cache/premium-product-chain-progress.json");
const REPORT_PATH = path.join(PROJECT_ROOT, "scripts/.cache/premium-product-chain-report.json");
const DEEPSEEK_API_URL = "https://api.deepseek.com/chat/completions";
const MODEL = "deepseek-chat";
const RATE_LIMIT_MS = 600;

type SchemaRecord = Record<string, unknown> & {
  toolName?: string;
  premiumRequired?: boolean;
  title?: string;
  description?: string;
  inputs?: Array<{ id: string; unit?: string; label?: string; businessContext?: string }>;
  formulas?: Record<string, string>;
  outputs?: Record<string, unknown>;
};

type RepairPatch = {
  formulas: Record<string, string>;
  outputs: Record<string, unknown>;
};

type ProgressState = {
  repaired: string[];
  failed: Array<{ slug: string; reason: string }>;
  skipped: string[];
};

/** Detect if ALL formulas in a tool are simple product chains (no domain operations) */
function isProductChainOnly(
  formulas: Record<string, string>,
  inputIds: readonly string[],
): boolean {
  const expressions = Object.values(formulas).filter((v) => typeof v === "string");
  if (expressions.length === 0) return false;
  return expressions.every((expr) => {
    const hasNormalizedProduct = expr.includes("normalized_product") || expr.includes("adjustment_factor");
    const isSimpleMult = /^[\w\s*()]+$/.test(expr) && !expr.includes("+") && expr.split("*").length >= 2;
    return hasNormalizedProduct || isSimpleMult;
  });
}

function parseArgs() {
  let limit = 5;
  let offset = 0;
  let dryRun = false;
  let retryFailed = false;
  let processAll = false;
  let slugFilter: string | null = null;
  for (const arg of process.argv.slice(2)) {
    if (arg.startsWith("--limit=")) limit = Number(arg.slice(8)) || 5;
    else if (arg.startsWith("--offset=")) offset = Number(arg.slice(9)) || 0;
    else if (arg === "--dry-run") dryRun = true;
    else if (arg === "--retry-failed") retryFailed = true;
    else if (arg === "--all") processAll = true;
    else if (arg.startsWith("--slug=")) slugFilter = arg.slice(7);
  }
  if (processAll) limit = 999;
  return { limit: Math.min(Math.max(limit, 1), 999), offset: Math.max(offset, 0), dryRun, retryFailed, slugFilter };
}

function loadProgress(): ProgressState {
  if (!fs.existsSync(PROGRESS_PATH)) return { repaired: [], failed: [], skipped: [] };
  return JSON.parse(fs.readFileSync(PROGRESS_PATH, "utf8"));
}

function saveProgress(state: ProgressState): void {
  fs.mkdirSync(path.dirname(PROGRESS_PATH), { recursive: true });
  fs.writeFileSync(PROGRESS_PATH, JSON.stringify(state, null, 2));
}

function listProductChainPremiumSchemas(): string[] {
  const slugs: string[] = [];
  for (const file of fs.readdirSync(SCHEMAS_DIR).filter((f) => f.endsWith("-schema.json"))) {
    const raw = JSON.parse(fs.readFileSync(path.join(SCHEMAS_DIR, file), "utf8")) as SchemaRecord;
    if (!raw.premiumRequired) continue;
    const inputIds = (raw.inputs ?? []).map((i) => i.id);
    const formulas = (raw.formulas ?? {}) as Record<string, string>;
    if (Object.keys(formulas).length === 0) continue;
    if (isProductChainOnly(formulas, inputIds)) {
      slugs.push(raw.toolName ?? file.replace("-schema.json", ""));
    }
  }
  return slugs.sort();
}

function buildRepairPrompt(schema: SchemaRecord): string {
  const inputLines = (schema.inputs ?? [])
    .map((i) => {
      const ctx = i.businessContext ? ` — ${i.businessContext}` : "";
      return `- ${i.id} (${i.unit ?? "unit"}, type:${i.type}) — ${i.label ?? i.id}${ctx}`;
    })
    .join("\n");

  const currentFormulas = Object.entries(schema.formulas ?? {})
    .map(([k, v]) => `  ${k}: ${v}`)
    .join("\n");

  return `Generate REAL formulas for this premium industrial calculator. Current formulas are stub product chains.

Tool: ${schema.toolName}
Title: ${schema.title ?? schema.toolName}
Description: ${schema.description ?? ""}

Inputs:
${inputLines}

Current stub formulas:
${currentFormulas}

RULES:
1. formulas must be valid JS expressions with + - * / ** and Math.* only
2. Use ONLY numeric input ids (skip select/boolean type inputs)
3. At least 3 formula keys; primary key MUST be named "result"
4. outputs.primary MUST be "result"
5. outputs.breakdown: array of 2-4 formula key names (NOT "result")
6. outputs.unit: cost tools → USD, rates → %, time → hours, physical → matching unit
7. outputs.hiddenLossDrivers: array of 2 strings
8. outputs.suggestedActions: array of 2 strings
9. outputs.dataConfidenceAdjusted: "result"

Return EXACTLY this structure (no nested objects inside outputs):
{
  "formulas": { "result": "...", "metric_a": "...", "metric_b": "..." },
  "outputs": {
    "primary": "result",
    "breakdown": ["metric_a", "metric_b"],
    "unit": "USD",
    "hiddenLossDrivers": ["...", "..."],
    "suggestedActions": ["...", "..."],
    "dataConfidenceAdjusted": "result"
  }
}`;
}

function validatePatch(schema: SchemaRecord, patch: RepairPatch): string | null {
  const merged: SchemaRecord = {
    ...schema,
    formulas: patch.formulas,
    outputs: { ...(schema.outputs as object), ...patch.outputs },
  };
  const allInputIds = (schema.inputs ?? []).map((i) => i.id);
  // All input IDs for compilation (select/boolean also appear in formulas)
  const inputIds = allInputIds;
  // Only count numeric inputs for coverage check
  const numericInputIds = (schema.inputs ?? [])
    .filter((i) => i.type === "number" || i.type === "integer" || i.type === "count" || i.type === "currency" || i.type === "percent")
    .map((i) => i.id);
  const coverageCheckIds = numericInputIds.length >= 2 ? numericInputIds : allInputIds;
  const formulaKeys = Object.keys(patch.formulas);

  if (formulaKeys.length < 2) return "fewer than 2 formulas";
  const primary = patch.outputs.primary;
  if (typeof primary !== "string" || !patch.formulas[primary]) {
    const firstKey = formulaKeys[0];
    if (firstKey && !patch.outputs.primary) {
      (patch.outputs as Record<string, unknown>).primary = firstKey;
    } else {
      return "outputs.primary missing in formulas";
    }
  }

  const usedInputs = coverageCheckIds.filter((id) =>
    Object.values(patch.formulas).some((e) => e.includes(id)),
  ).length;
  if (inputIds.length >= 4 && usedInputs < Math.ceil(inputIds.length / 2)) {
    return `formulas use only ${usedInputs}/${inputIds.length} inputs`;
  }

  for (const [key, expression] of Object.entries(patch.formulas)) {
    const config = {
      inputIds,
      inputToAccess: (inputId: string) => `input.${toSafeVarName(inputId)}`,
      formulaKeys,
      selfKey: key,
    } as const;
    let compiled: string | null = null;
    try {
      compiled = compileFormulaExpression(expression, config);
    } catch (e) {
      return `formula ${key} threw: ${e instanceof Error ? e.message : String(e)}`;
    }
    if (!compiled) {
      return `formula ${key} does not compile (expr: ${expression.substring(0, 80)})`;
    }
    if (compiled.includes("Math.Math")) return `formula ${key} has Math.Math issue`;
  }

  if (isProductChainOnly(patch.formulas, inputIds)) {
    return "formulas still product chain after repair";
  }

  const industrial = validateIndustrialSchema(merged);
  const critical = industrial.errors.filter(
    (e) =>
      e.includes("stub sum placeholder") ||
      e.includes("incomplete domain model") ||
      e.includes("output unit mismatch"),
  );
  if (critical.length > 0) return critical.join("; ");

  return null;
}

async function callDeepSeek(prompt: string, apiKey: string): Promise<RepairPatch> {
  const response = await fetch(DEEPSEEK_API_URL, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${apiKey}`,
      "Content-Type": "application/json",
    },
    body: JSON.stringify({
      model: MODEL,
      messages: [
        {
          role: "system",
          content:
            "You are an ISO 9001 industrial engineer specialized in calculation formulas. Output ONLY valid JSON.",
        },
        { role: "user", content: prompt },
      ],
      temperature: 0.1,
      max_tokens: 2500,
      response_format: { type: "json_object" },
    }),
  });

  const payload = (await response.json()) as {
    choices?: Array<{ message?: { content?: string } }>;
    error?: { message?: string };
  };

  if (!response.ok) throw new Error(payload.error?.message ?? `HTTP ${response.status}`);
  const content = payload.choices?.[0]?.message?.content ?? "";
  const parsed = JSON.parse(repairJsonText(content)) as RepairPatch;
  if (!parsed.formulas || !parsed.outputs) throw new Error("model response missing formulas/outputs");
  return parsed;
}

async function repairSlug(slug: string, apiKey: string, dryRun: boolean): Promise<void> {
  const schemaPath = path.join(SCHEMAS_DIR, `${slug}-schema.json`);
  const schema = JSON.parse(fs.readFileSync(schemaPath, "utf8")) as SchemaRecord;
  const patch = await callDeepSeek(buildRepairPrompt(schema), apiKey);
  // Debug: log generated formulas
  console.log(`  DeepSeek response: formulas keys=${Object.keys(patch.formulas).join(", ")}`);
  console.log(`  outputs.primary=${patch.outputs.primary}, outputs.unit=${patch.outputs.unit}`);
  for (const [k, v] of Object.entries(patch.formulas)) {
    console.log(`    ${k}: ${v}`);
  }
  const error = validatePatch(schema, patch);
  if (error) throw new Error(error);

  if (dryRun) {
    console.log(`DRY OK ${slug}`);
    console.log(`  Formulas:`, JSON.stringify(patch.formulas, null, 2));
    return;
  }

  const nextSchema: SchemaRecord = {
    ...schema,
    formulas: patch.formulas,
    outputs: { ...(schema.outputs as object), ...patch.outputs },
  };
  fs.writeFileSync(schemaPath, `${JSON.stringify(nextSchema, null, 2)}\n`);

  const outPath = path.join(GENERATED_DIR, `${slug}.ts`);
  const compileFailures = generateFromSchemaFile(schemaPath, outPath);
  if (compileFailures > 0) throw new Error(`${compileFailures} formula compile fallback(s)`);
  console.log(`OK ${slug}`);
  console.log(`  Formulas:`, Object.keys(patch.formulas).join(", "));
  console.log(`  Output:`, patch.outputs.unit === "USD" ? `${patch.outputs.unit}` : patch.outputs.unit);
}

async function main(): Promise<void> {
  const { limit, offset, dryRun, retryFailed, slugFilter } = parseArgs();
  const apiKey = resolveDeepSeekApiKey();
  if (!apiKey) {
    console.error("BLOKER: DEEPSEEK_API_KEY missing in .env.local");
    process.exit(1);
  }

  const all = slugFilter ? [slugFilter] : listProductChainPremiumSchemas();
  const progress = loadProgress();
  const failedSlugs = new Set(progress.failed.map((r) => r.slug));
  const source = retryFailed ? [...failedSlugs] : all;
  const batch = source.slice(offset, offset + limit);
  const report: ProgressState = { repaired: [], failed: [], skipped: [] };

  console.log(`product-chain premium total=${all.length} batch=${batch.length} offset=${offset}`);
  if (dryRun) console.log("DRY RUN — no files will be modified\n");
  if (slugFilter) console.log(`Single tool: ${slugFilter}\n`);

  for (const slug of batch) {
    if (!retryFailed && progress.repaired.includes(slug)) {
      console.log(`SKIP ${slug} (already repaired)`);
      report.skipped.push(slug);
      continue;
    }
    if (progress.failed.some((f) => f.slug === slug) && !retryFailed) {
      console.log(`SKIP ${slug} (previous failure — use --retry-failed)`);
      report.skipped.push(slug);
      continue;
    }
    try {
      await repairSlug(slug, apiKey, dryRun);
      progress.repaired.push(slug);
      progress.failed = progress.failed.filter((r) => r.slug !== slug);
      report.repaired.push(slug);
      saveProgress(progress);
      await new Promise((r) => setTimeout(r, RATE_LIMIT_MS));
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      console.error(`FAIL ${slug}: ${reason}`);
      progress.failed = progress.failed.filter((r) => r.slug !== slug);
      progress.failed.push({ slug, reason });
      report.failed.push({ slug, reason });
      saveProgress(progress);
    }
  }

  fs.mkdirSync(path.dirname(REPORT_PATH), { recursive: true });
  fs.writeFileSync(
    REPORT_PATH,
    JSON.stringify({ generatedAt: new Date().toISOString(), offset, limit, ...report }, null, 2),
  );

  console.log(`\nrepaired=${report.repaired.length} failed=${report.failed.length} skipped=${report.skipped.length}`);
  if (report.failed.length > 0) process.exit(1);
}

main().catch((error) => {
  console.error(error instanceof Error ? error.message : String(error));
  process.exit(1);
});
